    #region 임시: 팁 미세조정

    private void AdjustTip(double dx, double dy, double dz)
    {
        var tip = _robotModel.ScrewdriverTipLocal;
        _robotModel.ScrewdriverTipLocal = new Point3D(tip.X + dx, tip.Y + dy, tip.Z + dz);

        // 녹색 팁 마커만 실시간 갱신 (판 재빌드는 "팁 로그"에서)
        UpdateTipMarker();
    }

    private void UpdateTipMarker()
    {
        var modelPos = _robotModel.GetEndEffectorPosition();

        if (_tipMarkerVisual == null)
        {
            // 녹색 구 마커 생성
            var mesh = CreateUnitSphereMesh(12, 8);
            var mat = new DiffuseMaterial(new SolidColorBrush(Color.FromArgb(230, 0, 255, 0)));
            var tg = new Transform3DGroup();
            tg.Children.Add(new ScaleTransform3D(12, 12, 12));
            tg.Children.Add(new TranslateTransform3D(modelPos.X, modelPos.Y, modelPos.Z));
            var model = new GeometryModel3D { Geometry = mesh, Material = mat, BackMaterial = mat, Transform = tg };
            _tipMarkerVisual = new ModelVisual3D { Content = model };
            Viewport3D.Children.Add(_tipMarkerVisual);
        }
        else
        {
            // 위치만 갱신
            var model = (GeometryModel3D)_tipMarkerVisual.Content;
            var tg = new Transform3DGroup();
            tg.Children.Add(new ScaleTransform3D(12, 12, 12));
            tg.Children.Add(new TranslateTransform3D(modelPos.X, modelPos.Y, modelPos.Z));
            model.Transform = tg;
        }
    }

    private void BtnTipXP_Click(object sender, RoutedEventArgs e) => AdjustTip(0.5, 0, 0);
    private void BtnTipXM_Click(object sender, RoutedEventArgs e) => AdjustTip(-0.5, 0, 0);
    private void BtnTipYP_Click(object sender, RoutedEventArgs e) => AdjustTip(0, 0.5, 0);
    private void BtnTipYM_Click(object sender, RoutedEventArgs e) => AdjustTip(0, -0.5, 0);
    private void BtnTipZP_Click(object sender, RoutedEventArgs e) => AdjustTip(0, 0, 0.5);
    private void BtnTipZM_Click(object sender, RoutedEventArgs e) => AdjustTip(0, 0, -0.5);

    private void BtnTipLog_Click(object sender, RoutedEventArgs e)
    {
        // FK 오프셋 재계산 + 판 재빌드
        if (_lastTcp[0] != 0 || _lastTcp[1] != 0 || _lastTcp[2] != 0)
        {
            var modelPos = _robotModel.GetEndEffectorPosition();
            var realPos = new Point3D(_lastTcp[0], _lastTcp[1], _lastTcp[2]);
            _fkOffset = modelPos - realPos;
            Rebuild3DWorkPlate();
            UpdateTipMarker();
        }

        var t = _robotModel.ScrewdriverTipLocal;
        AddLog("━━━ 팁 위치 확정값 ━━━");
        AddLog($"  ScrewdriverTipLocal = new Point3D({t.X:F1}, {t.Y:F1}, {t.Z:F1})");
        AddLog($"  FK오프셋 = ({_fkOffset.X:F1}, {_fkOffset.Y:F1}, {_fkOffset.Z:F1})");
        AddLog("━━━━━━━━━━━━━━━━━");
    }

    private static int _3dLogIndex;
    private void BtnTip3DLog_Click(object sender, RoutedEventArgs e)
    {
        var pos = _robotModel.GetEndEffectorPosition();
        _3dLogIndex++;
        AddLog($"━━━ 3D좌표 #{_3dLogIndex} ━━━");
        AddLog($"  new Point3D({pos.X:F1}, {pos.Y:F1}, {pos.Z:F1})");
        AddLog($"━━━━━━━━━━━━━━━━━");
    }

    #endregion

    #region 창 닫기

    private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
    {
        _scenarioRunner.Stop();
        _bridgeServer?.Stop();
        _robotClient.Dispose();
    }

    #endregion
}
